#include<bits/stdc++.h>
#define ll long long
using namespace std;
const ll MAXN=2e5+5;
struct node{
	ll w,id;
}a[MAXN];
bool cmp(node a,node b){
	if(a.w!=b.w) return a.w<b.w;
	return a.id<b.id;
}void Swap(node &a,node &b){node temp;temp=b,b=a,a=temp;}
ll nowid[MAXN],n,q;
int main(void){
	scanf("%lld%lld",&n,&q);
	for(ll i=1;i<=n;++i)scanf("%lld",&a[i].w),a[i].id=i;
	sort(a+1,a+1+n,cmp);
	for(ll i=1;i<=n;++i)nowid[a[i].id]=i;
	for(ll T=1,l,x,u;T<=q;++T){
		scanf("%lld%lld",&l,&x);
		if(l==1){
			scanf("%lld",&u),a[nowid[x]].w=u;
			for(ll j=n;j>=2;--j)
				if(cmp(a[j],a[j-1]))
					Swap(a[j],a[j-1]);
			for(ll j=2;j<=n;++j)
				if(cmp(a[j],a[j-1]))
					Swap(a[j],a[j-1]);
			for(ll i=1;i<=n;++i)nowid[a[i].id]=i;
		}
		else printf("%lld\n",nowid[x]);
	}
	return false;
}
